module.exports = function rateLimit(options = {}) {
  const {
    windowMs = 60 * 1000,
    max = 60,
    message = { message: 'Too many requests. Please try again later.' },
    standardHeaders = false,
    legacyHeaders = false
  } = options;

  const buckets = new Map();

  return (req, res, next) => {
    const key = req.ip || req.headers['x-forwarded-for'] || 'anonymous';
    const now = Date.now();
    const existingBucket = buckets.get(key);

    if (!existingBucket || existingBucket.resetAt <= now) {
      buckets.set(key, {
        count: 1,
        resetAt: now + windowMs
      });

      if (standardHeaders) {
        res.setHeader('RateLimit-Limit', max);
        res.setHeader('RateLimit-Remaining', max - 1);
      }

      if (legacyHeaders) {
        res.setHeader('X-RateLimit-Limit', max);
        res.setHeader('X-RateLimit-Remaining', max - 1);
      }

      return next();
    }

    if (standardHeaders) {
      res.setHeader('RateLimit-Limit', max);
      res.setHeader('RateLimit-Remaining', Math.max(0, max - existingBucket.count - 1));
    }

    if (legacyHeaders) {
      res.setHeader('X-RateLimit-Limit', max);
      res.setHeader('X-RateLimit-Remaining', Math.max(0, max - existingBucket.count - 1));
    }

    if (existingBucket.count >= max) {
      return res.status(429).json(message);
    }

    existingBucket.count += 1;
    return next();
  };
};
